// =====================================================
// STATE — Initialisation du state MathGen
// Reçoit maintenant DB_Graphes (harmonisé) + Candidat
// =====================================================

const inputs = $input.all();

// DB_Graphes retourne { graphDatabase: [...] }
const dbItem       = inputs.find(i => i.json.graphDatabase);
const graphDatabase = dbItem?.json?.graphDatabase || [];

// On initialise le state avec grade par défaut
// (Curriculum JSON prendra grade/trimester depuis Candidat)
return {
  state: {
    graph:      null,
    structure:  null,
    values:     null,
    computed:   null,
    semantic:   null,
    narrative:  null,
    validation: null,
    attempts:   0,
    grade:      "CM1"
  },
  graphDatabase,
  graphs: graphDatabase
};

// =====================================================
// PARSER — Parse LLM output + injecte next_stage="scenario"
// next_stage hardcodé ici pour éviter la dépendance au LLM
// =====================================================

return $input.all().map(item => {
  let rawOutput = item.json.output;

  let cleanJson = rawOutput
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  try {
    const parsedData = JSON.parse(cleanJson);

    // Injection du next_stage — ne pas laisser le LLM décider
    return {
      json: {
        ...parsedData,
        next_stage: 'scenario'
      }
    };
  } catch (error) {
    // En cas d'erreur de parsing, on force quand même l'avancement
    return {
      json: {
        state_update: {},
        next_stage: 'scenario',
        parse_error: 'Échec parsing JSON: ' + error.message,
        original: rawOutput
      }
    };
  }
});

// =====================================================
// CLEAN GRAPHS — Nettoyage et transmission
// =====================================================

const rawGraphDatabase = $json.graphDatabase || [];

return {
  state: $json.state,
  graphs: rawGraphDatabase,
  graphDatabase: rawGraphDatabase
};

