// =====================================================
// GET CONSTRAINTS 
// =====================================================

const curriculum    = $json.curriculum;
const graphDatabase = $json.graphDatabase || [];

function getConstraints(grade, trimester, operation) {
  if (!curriculum?.constraints?.[grade]?.[trimester]?.[operation])
    throw new Error(`Operation [${operation}] not allowed for ${grade} ${trimester}`);

  const opBlock = curriculum.constraints[grade][trimester][operation];
  if (opBlock.allowed !== true)
    throw new Error(`Operation [${operation}] explicitly forbidden`);

  return opBlock;
}

const grade      = $json.grade;
const trimester  = $json.trimester;
const operations = Array.isArray($json.operation)
  ? $json.operation
  : [$json.operation];

const allRules = {};
for (const op of operations) {
  allRules[op] = getConstraints(grade, trimester, op);
}

return [{
  json: {
    context: { grade, trimester, allowed_operations: operations },
    global_rules: curriculum.global_rules,
    all_operation_rules: allRules,
    graphDatabase
  }
}];

// =====================================================
// SELECTGRAPH — VERSION ANTI-CRASH TOTALE
// =====================================================

// 1️⃣ Récupération sécurisée du node précédent
const previousNode = $input.first();

if (!previousNode || !previousNode.json) {
  throw new Error("GET CONSTRAINTS output is undefined");
}

const constraints = previousNode.json;

// 2️⃣ Vérifications strictes
if (!constraints.graphDatabase) {
  throw new Error("graphDatabase is missing");
}

if (!Array.isArray(constraints.graphDatabase)) {
  throw new Error("graphDatabase is not an array");
}

if (!constraints.context?.allowed_operations) {
  throw new Error("allowed_operations missing in context");
}

const graphDB = constraints.graphDatabase;
const allowedOps = constraints.context.allowed_operations;

// 3️⃣ Fonction sécurisée
function graphUsesOnlyAllowed(graphLines, allowedOps) {

  if (!Array.isArray(graphLines)) return false;

  const opMap = {
    '+':'addition',
    '-':'subtraction',
    '*':'multiplication',
    '/':'division'
  };

  for (const line of graphLines) {

    if (!line.includes('=')) return false;

    const right = line.split('=')[1];
    if (!right) return false;

    const ops = right.match(/[+\-*/]/g) || [];

    for (const op of ops) {
      if (!allowedOps.includes(opMap[op])) {
        return false;
      }
    }
  }

  return true;
}

// 4️⃣ Filtrage
const candidates = graphDB.filter(g =>
  graphUsesOnlyAllowed(g.graph, allowedOps)
);

if (!Array.isArray(candidates)) {
  throw new Error("Candidates is not an array");
}

if (candidates.length === 0) {
  throw new Error("No compatible graphs found");
}

// 5️⃣ Sélection aléatoire sécurisée
const selected = candidates[Math.floor(Math.random() * candidates.length)];

return [{
  json: {
    graph: selected.graph,
    selectedStructure: selected.structure,
    all_operation_rules: constraints.all_operation_rules,
    global_rules: constraints.global_rules,
    context: constraints.context
  }
}];

// ============================================================
// INDUSTRIAL BACKWARD CONSTRAINT ENGINE
// Universal Graph + Curriculum Compliant
// ============================================================

// -------------------- UTILITIES --------------------

function randomInt(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function digitCount(n) {
  return Math.abs(n).toString().length;
}

function tokenize(expr) {
  return expr.match(/[A-Z]+|\d+|[\+\-\*\/\%\(\)]/g);
}

function precedence(op) {
  if (op === "+" || op === "-") return 1;
  if (op === "*" || op === "/" || op === "%") return 2;
  return 0;
}

function toRPN(tokens) {
  const output = [];
  const stack = [];

  for (const token of tokens) {
    if (/^[A-Z]+$/.test(token) || /^\d+$/.test(token)) {
      output.push(token);
    } else if ("+-*/%".includes(token)) {
      while (
        stack.length &&
        precedence(stack[stack.length - 1]) >= precedence(token)
      ) {
        output.push(stack.pop());
      }
      stack.push(token);
    } else if (token === "(") {
      stack.push(token);
    } else if (token === ")") {
      while (stack.length && stack[stack.length - 1] !== "(") {
        output.push(stack.pop());
      }
      stack.pop();
    }
  }

  while (stack.length) output.push(stack.pop());
  return output;
}

function buildAST(rpn) {
  const stack = [];

  for (const token of rpn) {
    if ("+-*/%".includes(token)) {
      const right = stack.pop();
      const left = stack.pop();
      stack.push({ type: "op", op: token, left, right });
    } else {
      stack.push({
        type: /^[A-Z]+$/.test(token) ? "var" : "const",
        value: token
      });
    }
  }

  return stack[0];
}

// -------------------- BACKTRACK CONTEXT --------------------

class Context {
  constructor() {
    this.values = {};
    this.stack = [];
  }

  checkpoint() {
    this.stack.push(JSON.stringify(this.values));
  }

  rollback() {
    this.values = JSON.parse(this.stack.pop());
  }

  assign(key, value) {
    if (
      this.values[key] !== undefined &&
      this.values[key] !== value
    ) {
      throw new Error("Conflict on variable " + key);
    }
    this.values[key] = value;
  }
}

// -------------------- STRATEGIES --------------------

const Strategies = {

  "+": function(node, desired, ctx, rules) {

    const rule = rules.addition;
    const range = rule.operands_range;

    for (let a = range.min; a <= range.max; a++) {
      const b = desired - a;
      if (b < range.min || b > range.max) continue;

      ctx.checkpoint();
      try {
        solveNode(node.left, a, ctx, rules);
        solveNode(node.right, b, ctx, rules);
        return;
      } catch (e) {
        ctx.rollback();
      }
    }

    throw new Error("Addition impossible");
  },

  "-": function(node, desired, ctx, rules) {

    const rule = rules.subtraction;
    const range = rule.subtrahend_range;

    for (let b = range.min; b <= range.max; b++) {
      const a = desired + b;

      if (
        a < rule.minuend_range.min ||
        a > rule.minuend_range.max
      ) continue;

      ctx.checkpoint();
      try {
        solveNode(node.left, a, ctx, rules);
        solveNode(node.right, b, ctx, rules);
        return;
      } catch (e) {
        ctx.rollback();
      }
    }

    throw new Error("Subtraction impossible");
  },

  "*": function(node, desired, ctx, rules) {

    const rule = rules.multiplication;

    for (
      let a = rule.multiplicand_range.min;
      a <= rule.multiplicand_range.max;
      a++
    ) {

      if (desired % a !== 0) continue;

      const b = desired / a;

      if (!rule.multiplier_digit_count.includes(digitCount(b)))
        continue;

      ctx.checkpoint();
      try {
        solveNode(node.left, a, ctx, rules);
        solveNode(node.right, b, ctx, rules);
        return;
      } catch (e) {
        ctx.rollback();
      }
    }

    throw new Error("Multiplication impossible");
  },

  "/": function(node, desired, ctx, rules) {

    const rule = rules.division;

    for (let d = rule.divisor_range.min; d <= rule.divisor_range.max; d++) {

      if (!rule.divisor_digit_count.includes(digitCount(d)))
        continue;

      const dividend = desired * d;

      if (
        dividend < rule.dividend_range.min ||
        dividend > rule.dividend_range.max
      ) continue;

      ctx.checkpoint();
      try {
        solveNode(node.left, dividend, ctx, rules);
        solveNode(node.right, d, ctx, rules);
        return;
      } catch (e) {
        ctx.rollback();
      }
    }

    throw new Error("Division impossible");
  },

  "%": function(node, desired, ctx, rules) {

    for (let divisor = 2; divisor <= 20; divisor++) {

      if (desired >= divisor) continue;

      for (let q = 1; q <= 50; q++) {

        const dividend = divisor * q + desired;

        ctx.checkpoint();
        try {
          solveNode(node.left, dividend, ctx, rules);
          solveNode(node.right, divisor, ctx, rules);
          return;
        } catch (e) {
          ctx.rollback();
        }
      }
    }

    throw new Error("Remainder impossible");
  }

};

// -------------------- NODE SOLVER --------------------

function solveNode(node, desiredValue, ctx, rules) {

  if (node.type === "const") {
    if (Number(node.value) !== desiredValue)
      throw new Error("Constant mismatch");
    return;
  }

  if (node.type === "var") {
    ctx.assign(node.value, desiredValue);
    return;
  }

  if (!Strategies[node.op])
    throw new Error("Operator not supported: " + node.op);

  Strategies[node.op](node, desiredValue, ctx, rules);
}

// -------------------- GLOBAL VALIDATION --------------------

function validateGlobal(values, rules, globalRules) {

  if (globalRules?.natural_numbers_only) {
    for (const v of Object.values(values)) {
      if (!Number.isInteger(v) || v < 0)
        throw new Error("Global natural number violation");
    }
  }

  // Validate result ranges
  if (rules.addition?.result_range) {
    for (const k in values) {
      if (typeof values[k] !== "number") continue;
    }
  }
}

// -------------------- MAIN ENGINE --------------------

function solveGraph(graph, rules, globalRules) {

  const ctx = new Context();

  const MAX_ATTEMPTS = 20;

  for (let attempt = 0; attempt < MAX_ATTEMPTS; attempt++) {

    ctx.values = {};

    try {

      for (let i = graph.length - 1; i >= 0; i--) {

        const [left, right] = graph[i].split("=");

        const leftVar = left.trim();
        const expr = right.trim();

        const tokens = tokenize(expr);
        const rpn = toRPN(tokens);
        const ast = buildAST(rpn);

        let desired;

        if (i === graph.length - 1) {

          const rule =
            rules.addition ||
            rules.subtraction ||
            rules.multiplication ||
            rules.division;

          desired = randomInt(
            rule.result_range.min,
            rule.result_range.max
          );

        } else {
          desired = ctx.values[leftVar];
        }

        solveNode(ast, desired, ctx, rules);
        ctx.assign(leftVar, desired);
      }

      validateGlobal(ctx.values, rules, globalRules);

      return ctx.values;

    } catch (e) {
      continue;
    }
  }

  throw new Error("Industrial solver failed after retries");
}

// -------------------- EXECUTION --------------------

const graph = $json.graph;
const rules = $json.all_operation_rules;
const globalRules = $json.global_rules;

const values = solveGraph(graph, rules, globalRules);

return [{
  json: {
    ...$json,
    values
  }
}];

const rulesByOp = $json.all_operation_rules || {};

let activeUnitType = null;
let unitConfig     = null;

// On parcourt toutes les opérations actives
for (const opName of Object.keys(rulesByOp)) {

  const operationRules = rulesByOp[opName];

  if (!operationRules) continue;

  for (const type of ["length","mass","capacity","time"]) {

    if (operationRules?.[type]?.allowed === true) {

      activeUnitType = type;
      unitConfig     = operationRules[type];
      break;
    }
  }

  if (activeUnitType) break;
}

// Si aucune unité activée → sortie propre
if (!activeUnitType) {
  return [{ json: { ...$json, units_applied: false } }];
}

return [{
  json: {
    ...$json,
    units_applied: true,
    active_unit_type: activeUnitType,
    unit_config: unitConfig
  }
}];

// =====================================================
// UNIVERSAL VALIDATOR — VERSION ROBUSTE
// =====================================================

const { graph, values } = $json;

if (!graph || !values) {
  throw new Error("Missing graph or values");
}

// Sécurisation
function safeEvaluate(expr, vals) {

  const variables = Object.keys(vals);

  // Vérifie que toutes les variables de l'expression existent
  const usedVars = expr.match(/[A-Z][A-Z0-9_]*/g) || [];

  for (const v of usedVars) {
    if (!(v in vals)) {
      throw new Error(`Variable ${v} is missing in values`);
    }
  }

  return Function(...variables, `return ${expr};`)(...Object.values(vals));
}

for (const line of graph) {

  const [left, right] = line.split("=");

  if (!left || !right) {
    throw new Error(`Invalid equation format: ${line}`);
  }

  const leftVar = left.trim();
  const expr    = right.trim();

  if (!(leftVar in values)) {
    throw new Error(`Missing computed value for ${leftVar}`);
  }

  const expected = values[leftVar];
  const computed = safeEvaluate(expr, values);

  if (computed !== expected) {
    throw new Error(`Mismatch in equation: ${line}`);
  }
}

return [{
  json: {
    ...$json,
    validated: true
  }
}];

// =====================================================
// STATE ADAPTER — Pont entre le pipeline corrigé et MathGen
// Convertit notre format de sortie en state{} MathGen
// =====================================================

const data = $json;

// Reconstruct MathGen-compatible computed object from all graph values
const computed = { ...data.values };

// Build MathGen state object
const state = {
  // Core numeric data (used by Semantic Agent, Explanation, Audit)
  graph:     data.selectedStructure || { equations: data.graph, target_variable: "TARGET" },
  structure: data.selectedStructure || { equations: data.graph, target_variable: "TARGET", max_steps: data.graph?.length || 1 },
  values:    Object.fromEntries(
    Object.entries(data.values || {}).filter(([k]) => k !== "TARGET" && !k.startsWith("S"))
  ),
  computed:  computed,
  // Unit info (used by Semantic Agent for context)
  internal:  data.internal || null,
  // Curriculum context
  grade:     data.context?.grade     || "CM1",
  trimester: data.context?.trimester || "T3",
  operation: data.context?.operation || "addition",
  // Validation result
  validation: {
    valid:  data.validated === true,
    score:  data.validated === true ? 100 : 0,
    issues: []
  },
  // Placeholders for downstream agents
  semantic:  null,
  narrative: null,
  solution:  null,
  attempts:  0,
    };

return [{ json: { state } }];

const graphDatabase = $('DB_Graphes').first().json.graphDatabase || [];

return [{ json: {
  graphDatabase,          // ← on conserve le flux
  constraints: {
    grade: "5AP",
    trimester: "T3",
    allowed_operations: ["addition", "multiplication", "division"]
  }
}}];

// =====================================================
// PARSER CONTEXT — Parse context suggestions output
// =====================================================

return $input.all().map(item => {
  let rawOutput = item.json.output;

  let cleanJson = rawOutput
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  try {
    const parsedData = JSON.parse(cleanJson);

    return {
      json: {
        ...parsedData,
        next_stage: 'scenario'
      }
    };
  } catch (error) {
    // En cas d'erreur, on utilise un contexte par défaut
    return {
      json: {
        state_update: {
          context_suggestions: [{
            theme: "daily_life",
            description: "Situation de vie quotidienne",
            rationale: "Contexte générique applicable",
            cultural_fit: "Adapté à tous les niveaux"
          }],
          recommended_context: "daily_life"
        },
        next_stage: 'scenario',
        parse_error: 'Échec parsing JSON context: ' + error.message
      }
    };
  }
});

const previousState = $('Dispatcher').first().json.state;
const previousData = $('Dispatcher').first().json;  // ← IMPORTANT: récupérer TOUT
const input = $input.first().json;

function deepMerge(target, source) {
  if (!source) return target;

  const output = { ...target };

  Object.keys(source).forEach(key => {
    if (
      source[key] &&
      typeof source[key] === 'object' &&
      !Array.isArray(source[key]) &&
      target[key]
    ) {
      output[key] = deepMerge(target[key], source[key]);
    } else {
      output[key] = source[key];
    }
  });

  return output;
}

const mergedState = deepMerge(previousState, input.state_update || {});

// ✅ CORRECTION: Retourner state + graphDatabase + graphs
return {
  state: {
    ...mergedState,
    meta: {
      ...mergedState.meta,
      stage: input.next_stage || mergedState.meta.stage
    }
  },
  graphDatabase: previousData.graphDatabase || [],  // ← AJOUTÉ
  graphs: previousData.graphs || []                  // ← AJOUTÉ
};
